/**
 * OPFS Sync Worker — optional bidirectional mirror between VFS and real OPFS.
 *
 * Spawned by the server worker when opfsSync is enabled.
 * Receives mutation events from the server, writes them to real OPFS files.
 * Uses FileSystemObserver to detect external OPFS changes and syncs them back.
 */

import { coalesceWriteIndex } from './opfs-sync-plan.js';

interface SyncEvent {
  op: 'write' | 'delete' | 'mkdir' | 'rename';
  path: string;
  newPath?: string;
  data?: ArrayBuffer;
  ts: number;
}

let serverPort: MessagePort;
let mirrorRoot: FileSystemDirectoryHandle;

// Normalize path: resolve "." and "..", ensure leading /, collapse //, strip trailing /
function normalizePath(p: string): string {
  if (p.charCodeAt(0) !== 47) p = '/' + p;
  if (p.indexOf('//') !== -1) p = p.replace(/\/\/+/g, '/');
  // Resolve "." and ".." segments
  if (p.indexOf('/.') !== -1) {
    const parts = p.split('/');
    const resolved: string[] = [];
    for (const part of parts) {
      if (part === '.' || part === '') continue;
      if (part === '..') { resolved.pop(); continue; }
      resolved.push(part);
    }
    p = '/' + resolved.join('/');
  }
  if (p.length > 1 && p.charCodeAt(p.length - 1) === 47) p = p.slice(0, -1);
  return p || '/';
}

// Split a normalized path into segments safe for OPFS (no empty, ".", or ".." entries)
function pathSegments(p: string): string[] {
  return normalizePath(p).split('/').filter(Boolean);
}

// Echo suppression — two structures:
//
// pendingPaths (Set): paths currently in the queue or being processed.
//   Added on enqueue, removed after OPFS operation completes.
//   No timeout — stays as long as the item is in the queue.
//   Prevents false externals when queue takes >1s (e.g., 500-file batches).
//
// completedPaths (Map<path, timestamp>): paths recently written by us.
//   Added when processing completes, removed ONLY by periodic cleanup.
//   Grace window catches delayed/batched observer events after processing.
//
// Parent path check (opt-in): if /dir was deleted by us, /dir/file disappearing
// is also our echo (recursive removeEntry fires per-child events).
// ONLY used for 'disappeared' events — NOT for 'appeared'/'modified', since
// creating /dir doesn't mean /dir/new-file appearing is our echo.

const pendingPaths = new Set<string>();
const completedPaths = new Map<string, number>();
const GRACE_MS = 3000;

function trackPending(path: string): void {
  pendingPaths.add(normalizePath(path));
}

function untrackPending(path: string): void {
  pendingPaths.delete(normalizePath(path));
}

function trackCompleted(path: string): void {
  completedPaths.set(normalizePath(path), Date.now());
}

function isOurEcho(path: string, checkParents = false): boolean {
  path = normalizePath(path);
  const now = Date.now();

  // Check exact path
  if (pendingPaths.has(path)) return true;
  const ts = completedPaths.get(path);
  if (ts && now - ts < GRACE_MS) return true;

  // Walk up parent paths — ONLY for 'disappeared' events.
  // Handles recursive delete cascading: removeEntry(dir, {recursive:true})
  // fires individual 'disappeared' for every child file.
  // NOT used for 'appeared'/'modified' — a parent being tracked doesn't mean
  // a new file appearing inside it is our echo (could be genuinely external).
  if (checkParents) {
    let parent = path;
    while (true) {
      const slash = parent.lastIndexOf('/');
      if (slash <= 0) break;
      parent = parent.substring(0, slash);
      if (pendingPaths.has(parent)) return true;
      const pts = completedPaths.get(parent);
      if (pts && now - pts < GRACE_MS) return true;
    }
  }

  return false;
}

// Periodic cleanup — the ONLY way completedPaths entries get removed
setInterval(() => {
  const cutoff = Date.now() - GRACE_MS;
  for (const [p, ts] of completedPaths) {
    if (ts < cutoff) completedPaths.delete(p);
  }
}, 5000);

// Event queue — process one at a time, in order
const queue: SyncEvent[] = [];
let processing = false;

function enqueue(event: SyncEvent): void {
  trackPending(event.path);
  if (event.op === 'rename' && event.newPath) {
    trackPending(event.newPath);
  }

  // Coalesce bursts of 'write' events for the same path that are still
  // waiting in the queue. Each write event carries a full-file
  // ArrayBuffer — under backpressure (slow OPFS, big files) the queue
  // can otherwise hold many superseded buffers at once. Replacing the
  // pending event's payload with the newest drops the stale buffer for
  // GC while preserving queue ordering for non-write ops.
  //
  // Note: the event at index 0 may already be mid-flight inside
  // processNext (after its `queue.shift()`), so we only scan what's
  // still queued.
  if (event.op === 'write') {
    // Coalesce onto a still-queued write for the same path — but only if no
    // delete/rename/mkdir for it sits in between, which would otherwise reorder
    // this write ahead of that op and lose the file (see coalesceWriteIndex).
    const idx = coalesceWriteIndex(queue, event.path);
    if (idx !== -1) {
      queue[idx].data = event.data;
      queue[idx].ts = event.ts;
      return;
    }
  }

  queue.push(event);
  if (!processing) processNext();
}

async function applyEvent(event: SyncEvent): Promise<void> {
  switch (event.op) {
    case 'write':
      if (event.data) {
        await writeToOPFS(event.path, event.data);
      } else {
        // No data but file should still exist (empty file like .gitkeep)
        await writeToOPFS(event.path, new ArrayBuffer(0));
      }
      break;
    case 'delete':
      await deleteFromOPFS(event.path);
      break;
    case 'mkdir':
      await mkdirInOPFS(event.path);
      break;
    case 'rename':
      await renameInOPFS(event.path, event.newPath!);
      break;
  }
}

// Transient OPFS failures (WebKit throws NoModificationAllowedError / NotFound
// under sync-access-handle contention where Chromium never does — see the
// coalescing note above) must NOT silently drop a mirror op, or the OPFS file
// diverges permanently from the authoritative VFS. Retry before giving up;
// writeToOPFS truncates first and delete/mkdir are idempotent, so re-applying
// is safe. (renameInOPFS swallows its own errors and has its own retries.)
const MIRROR_MAX_ATTEMPTS = 4;

async function processNext(): Promise<void> {
  if (queue.length === 0) {
    processing = false;
    return;
  }
  processing = true;

  const event = queue.shift()!;

  for (let attempt = 1; attempt <= MIRROR_MAX_ATTEMPTS; attempt++) {
    try {
      await applyEvent(event);
      break;
    } catch (err) {
      if (attempt === MIRROR_MAX_ATTEMPTS) {
        console.warn('[opfs-sync] mirror failed after retries:', event.op, event.path, err);
        break;
      }
      await new Promise((r) => setTimeout(r, 10 * attempt));
    }
  }

  // Move from pending → completed (starts grace window for delayed observer events)
  untrackPending(event.path);
  trackCompleted(event.path);
  if (event.op === 'rename' && event.newPath) {
    untrackPending(event.newPath);
    trackCompleted(event.newPath);
  }

  processNext();
}

async function ensureParentDirs(path: string): Promise<FileSystemDirectoryHandle> {
  const parts = pathSegments(path);
  parts.pop(); // Remove filename

  let dir = mirrorRoot;
  for (const part of parts) {
    dir = await dir.getDirectoryHandle(part, { create: true });
  }
  return dir;
}

function basename(path: string): string {
  const parts = pathSegments(path);
  return parts[parts.length - 1] || '';
}

async function writeToOPFS(path: string, data: ArrayBuffer): Promise<void> {
  const dir = await ensureParentDirs(path);
  const name = basename(path);
  const fileHandle = await dir.getFileHandle(name, { create: true });
  // Use createSyncAccessHandle for reliable writes in Worker context
  // (createWritable can silently fail in nested workers for OPFS files)
  const accessHandle = await fileHandle.createSyncAccessHandle();
  try {
    accessHandle.truncate(0);
    accessHandle.write(new Uint8Array(data), { at: 0 });
    accessHandle.flush();
  } finally {
    accessHandle.close();
  }
}

async function deleteFromOPFS(path: string): Promise<void> {
  try {
    const dir = await navigateToParent(path);
    await dir.removeEntry(basename(path), { recursive: true });
  } catch {
    // File may not exist in OPFS — that's fine
  }
}

async function mkdirInOPFS(path: string): Promise<void> {
  let dir = mirrorRoot;
  for (const part of pathSegments(path)) {
    dir = await dir.getDirectoryHandle(part, { create: true });
  }
}

// Chunk size for the chunked rename copy. Caps peak memory during a
// rename at this size rather than the full file size.
const RENAME_CHUNK = 2 * 1024 * 1024;

async function renameInOPFS(oldPath: string, newPath: string): Promise<void> {
  // OPFS has no native rename — copy + delete. Try the file path first
  // (which is the common case: write/copy/etc events). If `oldPath` is
  // actually a directory (e.g. Vite committing `.vite/deps_temp_X` →
  // `.vite/deps`), `getFileHandle` rejects with TypeMismatchError —
  // fall through to the directory-aware branch which recursively walks
  // the source tree.
  let srcAccess: FileSystemSyncAccessHandle | null = null;
  let dstAccess: FileSystemSyncAccessHandle | null = null;
  // Definite-assignment: both are set inside the retry loop before
  // `resolvedFile` flips true, and the file-rename path below is only
  // reached when resolvedFile === true. TS can't correlate the flag with
  // the assignments, so assert it.
  let oldDir!: FileSystemDirectoryHandle;
  let oldHandle!: FileSystemFileHandle;
  // Resolve the source as a FILE. Two failure modes must be distinguished:
  //   • TypeMismatchError  → oldPath is genuinely a DIRECTORY → dir branch.
  //   • NotFoundError      → the file isn't visible (yet). On Safari, OPFS has
  //                          a brief consistency lag between a createSyncAccess-
  //                          Handle write and a subsequent getFileHandle, so a
  //                          just-written source (e.g. `printf x > a; mv a b`)
  //                          can momentarily report NotFound. Treating that as
  //                          "it's a directory" (the old behavior) sent it down
  //                          the dir branch, which ALSO failed →
  //                          "rename (dir) failed: … NotFoundError". Instead we
  //                          RETRY the file lookup a few times to let OPFS catch
  //                          up, then fall back to the dir branch only as a last
  //                          resort.
  let resolvedFile = false;
  let lastErr: any = null;
  for (let attempt = 0; attempt < 6; attempt++) {
    try {
      oldDir = await navigateToParent(oldPath);
      oldHandle = await oldDir.getFileHandle(basename(oldPath));
      resolvedFile = true;
      break;
    } catch (err: any) {
      lastErr = err;
      const msg = err?.message || '';
      const isDir =
        err?.name === 'TypeMismatchError' ||
        msg.includes('TypeMismatch') ||
        msg.includes('not a file') ||
        msg.includes('not an entry of requested type');
      if (isDir) {
        try {
          await renameDirInOPFS(oldPath, newPath);
        } catch (dirErr) {
          console.warn('[opfs-sync] rename (dir) failed:', oldPath, '→', newPath, dirErr);
        }
        return;
      }
      // NotFoundError (or other transient): yield and retry so the OPFS
      // mirror can catch up with the just-written source (Safari lag).
      if (attempt < 5) {
        await new Promise((r) => setTimeout(r, 8 * (attempt + 1)));
        continue;
      }
    }
  }
  if (!resolvedFile) {
    // Exhausted file retries. Last resort: it may be a directory that Safari
    // reported via NotFound rather than TypeMismatch — try the dir branch once.
    try {
      await renameDirInOPFS(oldPath, newPath);
      return;
    } catch {
      /* fall through to the warning below */
    }
    console.warn('[opfs-sync] rename failed (source not found after retries):', oldPath, '→', newPath, lastErr);
    return;
  }
  // File rename — copy through two sync access handles in fixed-size
  // chunks so a rename of a large file doesn't require materializing
  // the whole file in memory.
  try {
    srcAccess = await oldHandle.createSyncAccessHandle();
    const size = srcAccess.getSize();

    const newDir = await ensureParentDirs(newPath);
    const newHandle = await newDir.getFileHandle(basename(newPath), { create: true });
    dstAccess = await newHandle.createSyncAccessHandle();
    dstAccess.truncate(0);

    if (size > 0) {
      const chunk = new Uint8Array(Math.min(size, RENAME_CHUNK));
      let offset = 0;
      while (offset < size) {
        const len = Math.min(chunk.length, size - offset);
        const view = len === chunk.length ? chunk : chunk.subarray(0, len);
        srcAccess.read(view, { at: offset });
        dstAccess.write(view, { at: offset });
        offset += len;
      }
    }
    dstAccess.flush();

    // Release handles before removeEntry — can't unlink a file that
    // still has an open sync access handle.
    try { dstAccess.close(); } catch { /* ignore */ }
    dstAccess = null;
    try { srcAccess.close(); } catch { /* ignore */ }
    srcAccess = null;

    await removeEntryWithRetry(oldDir, basename(oldPath));
  } catch (err) {
    console.warn('[opfs-sync] rename failed:', oldPath, '→', newPath, err);
  } finally {
    if (dstAccess) { try { dstAccess.close(); } catch { /* ignore */ } }
    if (srcAccess) { try { srcAccess.close(); } catch { /* ignore */ } }
  }
}

/**
 * Directory-aware rename in OPFS — walks the source tree and copies
 * each file via sync access handles, then deletes the source. Used
 * when `renameInOPFS` discovers oldPath is a directory rather than
 * a file.
 *
 * Replaces the destination directory entirely if it already exists,
 * matching Node.js rename semantics for directories.
 */
async function renameDirInOPFS(oldPath: string, newPath: string): Promise<void> {
  // Resolve the source directory handle.
  const oldParent = await navigateToParent(oldPath);
  const srcDir = await oldParent.getDirectoryHandle(basename(oldPath));

  // Wipe the target if it exists (file or directory) so the rename
  // is a clean replace, then recreate it as a fresh directory.
  const newParent = await ensureParentDirs(newPath);
  try {
    await newParent.removeEntry(basename(newPath), { recursive: true });
  } catch (e: any) {
    // NotFoundError is expected when target doesn't exist; everything
    // else we let bubble (caller logs a single warning).
    if (e?.name !== 'NotFoundError') throw e;
  }
  const dstDir = await newParent.getDirectoryHandle(basename(newPath), { create: true });

  await copyDirContents(srcDir, dstDir);

  // Remove the now-copied source. A rename must not leave the original behind,
  // so retry a few times to ride out a transient OPFS lock/consistency hiccup
  // (a child handle that hasn't fully released yet) before giving up.
  await removeEntryWithRetry(oldParent, basename(oldPath), { recursive: true });
}

/**
 * removeEntry with a short retry loop. OPFS occasionally rejects a removeEntry
 * immediately after a bulk copy/close with a transient lock error; a couple of
 * retries with backoff let the handles settle so the source is actually gone.
 */
async function removeEntryWithRetry(
  dir: FileSystemDirectoryHandle,
  name: string,
  options?: { recursive?: boolean },
): Promise<void> {
  let lastErr: any = null;
  for (let attempt = 0; attempt < 4; attempt++) {
    try {
      await dir.removeEntry(name, options);
      return;
    } catch (err: any) {
      if (err?.name === 'NotFoundError') return; // already gone — success
      lastErr = err;
      await new Promise((r) => setTimeout(r, 10 * (attempt + 1)));
    }
  }
  throw lastErr;
}

/**
 * Recursively copy every entry under `src` into `dst`.
 * Uses sync access handles for files (chunked) so memory peaks at
 * RENAME_CHUNK regardless of file size.
 */
async function copyDirContents(
  src: FileSystemDirectoryHandle,
  dst: FileSystemDirectoryHandle,
): Promise<void> {
  // entries() is async-iterable: [name, FileSystemHandle]
  for await (const [name, handle] of (src as any).entries()) {
    if (handle.kind === 'directory') {
      const childDst = await dst.getDirectoryHandle(name, { create: true });
      await copyDirContents(handle as FileSystemDirectoryHandle, childDst);
    } else {
      const fileHandle = handle as FileSystemFileHandle;
      const dstFile = await dst.getFileHandle(name, { create: true });
      let srcAccess: FileSystemSyncAccessHandle | null = null;
      let dstAccess: FileSystemSyncAccessHandle | null = null;
      try {
        srcAccess = await fileHandle.createSyncAccessHandle();
        dstAccess = await dstFile.createSyncAccessHandle();
        const size = srcAccess.getSize();
        dstAccess.truncate(0);
        if (size > 0) {
          const chunk = new Uint8Array(Math.min(size, RENAME_CHUNK));
          let offset = 0;
          while (offset < size) {
            const len = Math.min(chunk.length, size - offset);
            const view = len === chunk.length ? chunk : chunk.subarray(0, len);
            srcAccess.read(view, { at: offset });
            dstAccess.write(view, { at: offset });
            offset += len;
          }
        }
        dstAccess.flush();
      } finally {
        if (dstAccess) { try { dstAccess.close(); } catch { /* ignore */ } }
        if (srcAccess) { try { srcAccess.close(); } catch { /* ignore */ } }
      }
    }
  }
}

async function navigateToParent(path: string): Promise<FileSystemDirectoryHandle> {
  const parts = pathSegments(path);
  parts.pop();

  let dir = mirrorRoot;
  for (const part of parts) {
    dir = await dir.getDirectoryHandle(part);
  }
  return dir;
}

// ========== FileSystemObserver for external changes ==========

function setupObserver(): void {
  if (typeof FileSystemObserver === 'undefined') {
    console.warn('[opfs-sync] FileSystemObserver not available — external changes will not be detected');
    return;
  }

  console.log('[opfs-sync] Setting up FileSystemObserver on mirrorRoot:', mirrorRoot.name || '(opfs-root)');

  const observer = new FileSystemObserver((records) => {
    //console.log(`[opfs-sync] observer fired: ${records.length} record(s), pending=${pendingPaths.size}, completed=${completedPaths.size}`);
    for (const record of records) {
      const path = normalizePath('/' + record.relativePathComponents.join('/'));

      // Skip VFS binary file and internal files
      if (path === '/.vfs.bin' || path === '/.vfs' || path.startsWith('/.vfs')) continue;

      // Echo suppression — check parents only for 'disappeared' (recursive delete cascading)
      const isDelete = record.type === 'disappeared';
      if (isOurEcho(path, isDelete)) {
        //console.log('[opfs-sync] suppressed (echo):', record.type, path);
        continue;
      }

      //console.log('[opfs-sync] external:', record.type, path);
      switch (record.type) {
        case 'appeared':
        case 'modified':
          syncExternalChange(path, record.changedHandle);
          break;
        case 'disappeared':
          syncExternalDelete(path);
          break;
        case 'moved': {
          const from = normalizePath('/' + record.relativePathMovedFrom!.join('/'));
          //console.log('[opfs-sync] external: moved from', from, '→', path);
          syncExternalRename(from, path);
          break;
        }
      }
    }
  });

  observer.observe(mirrorRoot, { recursive: true });
}

async function syncExternalChange(path: string, handle: FileSystemHandle | null): Promise<void> {
  try {
    if (!handle || handle.kind !== 'file') return;

    const fileHandle = handle as FileSystemFileHandle;
    const file = await fileHandle.getFile();
    const data = await file.arrayBuffer();

    serverPort.postMessage({
      op: 'external-write',
      path,
      data,
      ts: Date.now(),
    }, [data]);
  } catch (err) {
    // File may have been deleted between observer event and our read, or
    // a sync access handle may be holding the lock — either is fine to skip
    console.warn('[opfs-sync] external change read failed:', path, err);
  }
}

function syncExternalDelete(path: string): void {
  serverPort.postMessage({
    op: 'external-delete',
    path,
    ts: Date.now(),
  });
}

function syncExternalRename(oldPath: string, newPath: string): void {
  serverPort.postMessage({
    op: 'external-rename',
    path: oldPath,
    newPath,
    ts: Date.now(),
  });
}

// ========== Initialization ==========

self.onmessage = async (e: MessageEvent) => {
  const msg = e.data;

  if (msg.type === 'init') {
    serverPort = e.ports[0];
    mirrorRoot = await navigator.storage.getDirectory();

    // Navigate to mirror root if specified
    if (msg.root && msg.root !== '/') {
      const segments = msg.root.split('/').filter(Boolean);
      for (const segment of segments) {
        mirrorRoot = await mirrorRoot.getDirectoryHandle(segment, { create: true });
      }
    }

    console.log('[opfs-sync] initialized with root:', msg.root || '/', 'mirrorRoot.name:', mirrorRoot.name || '(opfs-root)');

    // Set up FileSystemObserver
    setupObserver();

    // Listen for events from server
    serverPort.onmessage = (ev: MessageEvent) => {
      const event = ev.data as SyncEvent;
      enqueue(event);
    };
    serverPort.start();

    (self as unknown as Worker).postMessage({ type: 'ready' });
    return;
  }
};
